export * from './toggle-group.component';
export * from './toggle.component';
export * from './toggle.variants';
export * from './toggle.token';
export * from './toggle.imports';

import {
  booleanAttribute,
  ChangeDetectionStrategy,
  Component,
  computed,
  forwardRef,
  input,
  model,
  output,
  signal,
  ViewEncapsulation,
} from '@angular/core';
import { type ControlValueAccessor, NG_VALUE_ACCESSOR } from '@angular/forms';

import { cn, type ClassValue } from '{{alias}}/utils';
import { HB_TOGGLE_GROUP, type HbToggleGroupContext, type HbToggleItemRef } from './toggle.token';
import {
  toggleGroupConnectedClass,
  toggleGroupConnectedOutlineClass,
  type HbToggleGroupType,
  type HbToggleSize,
  type HbToggleVariant,
} from './toggle.variants';

@Component({
  selector: 'hb-toggle-group',
  template: `<ng-content />`,
  changeDetection: ChangeDetectionStrategy.OnPush,
  encapsulation: ViewEncapsulation.None,
  providers: [
    {
      provide: NG_VALUE_ACCESSOR,
      useExisting: forwardRef(() => HbToggleGroupComponent),
      multi: true,
    },
    { provide: HB_TOGGLE_GROUP, useExisting: forwardRef(() => HbToggleGroupComponent) },
  ],
  host: {
    role: 'group',
    '[class]': 'classes()',
    '[attr.data-slot]': "'toggle-group'",
    '[attr.aria-label]': 'hbAriaLabel() || null',
  },
  exportAs: 'hbToggleGroup',
})
export class HbToggleGroupComponent implements ControlValueAccessor, HbToggleGroupContext {
  readonly hbType = input<HbToggleGroupType>('single');
  readonly hbValue = model<unknown>(null);
  readonly hbVariant = input<HbToggleVariant>('default');
  readonly hbSize = input<HbToggleSize>('md');
  readonly hbDisabled = input(false, { transform: booleanAttribute });
  readonly hbConnected = input(true, { transform: booleanAttribute });
  readonly hbRollable = input(true, { transform: booleanAttribute });
  readonly hbAriaLabel = input<string>('');
  readonly class = input<ClassValue>('');

  readonly hbChange = output<unknown>();

  private readonly items = signal<HbToggleItemRef[]>([]);
  private readonly cvaDisabled = signal(false);
  private onChange: (value: unknown) => void = () => {};
  private onTouched: () => void = () => {};

  readonly type = this.hbType;
  readonly variant = this.hbVariant;
  readonly size = this.hbSize;
  readonly disabled = computed(() => this.hbDisabled() || this.cvaDisabled());

  protected readonly classes = computed(() =>
    cn(
      'inline-flex items-center',
      this.hbConnected()
        ? cn(
            toggleGroupConnectedClass,
            this.hbVariant() === 'outline' && toggleGroupConnectedOutlineClass,
          )
        : 'gap-1',
      this.class(),
    ),
  );

  private get selectionArray(): unknown[] {
    const v = this.hbValue();
    return Array.isArray(v) ? v : [];
  }

  isSelected(value: unknown): boolean {
    return this.hbType() === 'multiple'
      ? this.selectionArray.includes(value)
      : this.hbValue() === value;
  }
  toggle(value: unknown): void {
    if (this.disabled()) return;
    if (this.hbType() === 'multiple') {
      const current = this.selectionArray;
      const next = current.includes(value)
        ? current.filter((v) => v !== value)
        : [...current, value];
      this.commit(next);
    } else {
      const next = this.hbValue() === value ? (this.hbRollable() ? null : value) : value;
      this.commit(next);
    }
  }
  private commit(value: unknown): void {
    this.hbValue.set(value);
    this.onChange(value);
    this.onTouched();
    this.hbChange.emit(value);
  }

  registerItem(item: HbToggleItemRef): void {
    this.items.update((list) => [...list, item]);
  }
  unregisterItem(item: HbToggleItemRef): void {
    this.items.update((list) => list.filter((i) => i !== item));
  }
  private ordered(): HbToggleItemRef[] {
    return [...this.items()].sort((a, b) =>
      a.element().compareDocumentPosition(b.element()) & Node.DOCUMENT_POSITION_FOLLOWING ? -1 : 1,
    );
  }
  isActiveItem(item: HbToggleItemRef): boolean {
    const enabled = this.ordered().filter((i) => !i.disabled());
    const active = enabled.find((i) => this.isSelected(i.value())) ?? enabled[0];
    return active === item;
  }
  onItemKeydown(item: HbToggleItemRef, event: KeyboardEvent): void {
    const enabled = this.ordered().filter((i) => !i.disabled());
    const i = enabled.indexOf(item);
    if (i < 0) return;
    let target: HbToggleItemRef | undefined;
    switch (event.key) {
      case 'ArrowRight':
      case 'ArrowDown':
        target = enabled[(i + 1) % enabled.length];
        break;
      case 'ArrowLeft':
      case 'ArrowUp':
        target = enabled[(i - 1 + enabled.length) % enabled.length];
        break;
      case 'Home':
        target = enabled[0];
        break;
      case 'End':
        target = enabled[enabled.length - 1];
        break;
      default:
        return;
    }
    if (!target) return;
    event.preventDefault();
    target.element().focus();
  }
  markTouched(): void {
    this.onTouched();
  }

  writeValue(value: unknown): void {
    this.hbValue.set(value ?? (this.hbType() === 'multiple' ? [] : null));
  }
  registerOnChange(fn: (value: unknown) => void): void {
    this.onChange = fn;
  }
  registerOnTouched(fn: () => void): void {
    this.onTouched = fn;
  }
  setDisabledState(isDisabled: boolean): void {
    this.cvaDisabled.set(isDisabled);
  }
}

import {
  booleanAttribute,
  ChangeDetectionStrategy,
  Component,
  computed,
  DestroyRef,
  ElementRef,
  inject,
  input,
  model,
  output,
  ViewEncapsulation,
} from '@angular/core';
import { NgIcon } from '@ng-icons/core';

import { cn, type ClassValue } from '{{alias}}/utils';
import { HB_TOGGLE_GROUP, type HbToggleGroupContext, type HbToggleItemRef } from './toggle.token';
import {
  toggleVariants,
  type HbToggleSize,
  type HbToggleVariant,
} from './toggle.variants';

@Component({
  selector: 'hb-toggle',
  imports: [NgIcon],
  template: `
    @if (hbIcon()) {
      <ng-icon [name]="hbIcon()" />
    }
    <ng-content />
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
  encapsulation: ViewEncapsulation.None,
  host: {
    role: 'button',
    '[class]': 'classes()',
    '[attr.data-slot]': "'toggle'",
    '[attr.data-state]': "pressed() ? 'on' : 'off'",
    '[attr.aria-pressed]': 'pressed()',
    '[attr.aria-disabled]': 'isDisabled() || null',
    '[attr.data-disabled]': 'isDisabled() || null',
    '[attr.tabindex]': 'tabindex()',
    '(click)': 'onClick()',
    '(keydown)': 'onKeydown($event)',
  },
  exportAs: 'hbToggle',
})
export class HbToggleComponent {
  protected readonly group = inject<HbToggleGroupContext | null>(HB_TOGGLE_GROUP, {
    optional: true,
  });
  private readonly el = inject<ElementRef<HTMLElement>>(ElementRef);
  private readonly destroyRef = inject(DestroyRef);

  readonly hbPressed = model(false);
  readonly hbValue = input<unknown>(null);
  readonly hbVariant = input<HbToggleVariant | null>(null);
  readonly hbSize = input<HbToggleSize | null>(null);
  readonly hbDisabled = input(false, { transform: booleanAttribute });
  readonly hbIcon = input<string>('');
  readonly class = input<ClassValue>('');

  readonly hbChange = output<boolean>();

  private readonly ref: HbToggleItemRef = {
    value: () => this.hbValue(),
    element: () => this.el.nativeElement,
    disabled: () => this.hbDisabled(),
  };

  protected readonly pressed = computed(() =>
    this.group ? this.group.isSelected(this.hbValue()) : this.hbPressed(),
  );
  protected readonly isDisabled = computed(
    () => this.hbDisabled() || (this.group?.disabled() ?? false),
  );
  private readonly effVariant = computed<HbToggleVariant>(
    () => this.hbVariant() ?? this.group?.variant() ?? 'default',
  );
  private readonly effSize = computed<HbToggleSize>(
    () => this.hbSize() ?? this.group?.size() ?? 'md',
  );
  protected readonly tabindex = computed(() => {
    if (this.isDisabled()) return -1;
    if (this.group) return this.group.isActiveItem(this.ref) ? 0 : -1;
    return 0;
  });
  protected readonly classes = computed(() =>
    cn(toggleVariants({ variant: this.effVariant(), size: this.effSize() }), this.class()),
  );

  constructor() {
    if (this.group) {
      this.group.registerItem(this.ref);
      this.destroyRef.onDestroy(() => this.group?.unregisterItem(this.ref));
    }
  }

  protected onClick(): void {
    if (this.isDisabled()) return;
    if (this.group) {
      this.group.toggle(this.hbValue());
    } else {
      this.hbPressed.update((v) => !v);
    }
    this.hbChange.emit(this.pressed());
  }

  protected onKeydown(event: KeyboardEvent): void {
    if (event.key === 'Enter' || event.key === ' ') {
      event.preventDefault();
      this.onClick();
      return;
    }
    if (this.group) this.group.onItemKeydown(this.ref, event);
  }
}

import { HbToggleGroupComponent } from './toggle-group.component';
import { HbToggleComponent } from './toggle.component';

export const HbToggleImports = [HbToggleComponent, HbToggleGroupComponent] as const;

import { InjectionToken } from '@angular/core';

import type { HbToggleGroupType, HbToggleSize, HbToggleVariant } from './toggle.variants';

export interface HbToggleItemRef {
  value: () => unknown;
  element: () => HTMLElement;
  disabled: () => boolean;
}

export interface HbToggleGroupContext {
  readonly type: () => HbToggleGroupType;
  readonly variant: () => HbToggleVariant;
  readonly size: () => HbToggleSize;
  readonly disabled: () => boolean;
  isSelected(value: unknown): boolean;
  toggle(value: unknown): void;
  registerItem(item: HbToggleItemRef): void;
  unregisterItem(item: HbToggleItemRef): void;
  isActiveItem(item: HbToggleItemRef): boolean;
  onItemKeydown(item: HbToggleItemRef, event: KeyboardEvent): void;
  markTouched(): void;
}

export const HB_TOGGLE_GROUP = new InjectionToken<HbToggleGroupContext>('HB_TOGGLE_GROUP');

import { cva, type VariantProps } from 'class-variance-authority';

export const toggleVariants = cva(
  'inline-flex shrink-0 cursor-pointer select-none items-center justify-center gap-2 rounded-md font-medium whitespace-nowrap outline-none transition-colors focus-visible:ring-[3px] focus-visible:ring-ring/50 disabled:pointer-events-none disabled:opacity-50 data-[disabled]:pointer-events-none data-[disabled]:opacity-50 hover:bg-muted hover:text-foreground data-[state=on]:bg-accent data-[state=on]:text-accent-foreground [&_ng-icon]:shrink-0',
  {
    variants: {
      variant: {
        default: 'bg-transparent',
        outline: 'border border-input bg-transparent shadow-xs hover:bg-accent',
      },
      size: {
        xs: 'h-7 min-w-7 gap-1.5 px-1.5 text-xs [&_ng-icon]:text-sm',
        sm: 'h-8 min-w-8 px-2 text-xs [&_ng-icon]:text-base',
        md: 'h-9 min-w-9 px-2.5 text-sm [&_ng-icon]:text-lg',
        lg: 'h-10 min-w-10 px-3 text-sm [&_ng-icon]:text-xl',
        xl: 'h-11 min-w-11 px-4 text-base [&_ng-icon]:text-2xl',
      },
    },
    defaultVariants: { variant: 'default', size: 'md' },
  },
);

export type HbToggleVariant = NonNullable<VariantProps<typeof toggleVariants>['variant']>;
export type HbToggleSize = NonNullable<VariantProps<typeof toggleVariants>['size']>;
export type HbToggleGroupType = 'single' | 'multiple';

export const toggleGroupConnectedClass =
  '[&>[data-slot=toggle]]:rounded-none [&>[data-slot=toggle]:first-child]:rounded-l-md [&>[data-slot=toggle]:last-child]:rounded-r-md [&>[data-slot=toggle]]:focus-visible:z-10';

export const toggleGroupConnectedOutlineClass =
  '[&>[data-slot=toggle]:not(:first-child)]:-ml-px';

