import { ChangeDetectionStrategy, Component, signal } from '@angular/core';
import { provideIcons } from '@ng-icons/core';
import { phosphorBell, phosphorStar, phosphorTextB } from '@ng-icons/phosphor-icons/regular';

import { HbToggleImports } from '@herbst/ui';

@Component({
  selector: 'hb-demo-toggle-basic',
  imports: [HbToggleImports],
  viewProviders: [provideIcons({ phosphorTextB, phosphorStar, phosphorBell })],
  template: `
    <div class="flex flex-wrap items-center gap-3">
      <hb-toggle [(hbPressed)]="bold" hbIcon="phosphorTextB" (hbChange)="last.set($event)">
        Bold
      </hb-toggle>

      <hb-toggle hbVariant="outline" hbIcon="phosphorStar" hbSize="lg">Star</hb-toggle>

      <hb-toggle hbVariant="outline" hbSize="sm" [hbPressed]="true">Subscribed</hb-toggle>

      <hb-toggle hbIcon="phosphorBell" hbDisabled>Muted</hb-toggle>
    </div>

    <p class="mt-3 font-mono text-[12px] text-muted-foreground">
      bold: {{ bold() }} · last change: {{ last() }}
    </p>
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class HbDemoToggleBasicComponent {
  protected readonly bold = signal(false);
  protected readonly last = signal<boolean | string>('—');
}

import { ChangeDetectionStrategy, Component, signal } from '@angular/core';
import { provideIcons } from '@ng-icons/core';
import {
  phosphorTextB,
  phosphorTextItalic,
  phosphorTextStrikethrough,
  phosphorTextUnderline,
} from '@ng-icons/phosphor-icons/regular';

import { HbToggleImports } from '@herbst/ui';

@Component({
  selector: 'hb-demo-toggle-group-multiple',
  imports: [HbToggleImports],
  viewProviders: [
    provideIcons({
      phosphorTextB,
      phosphorTextItalic,
      phosphorTextUnderline,
      phosphorTextStrikethrough,
    }),
  ],
  template: `
    <div class="flex flex-col gap-4">
      <hb-toggle-group
        hbType="multiple"
        hbVariant="outline"
        hbSize="lg"
        hbAriaLabel="Text formatting"
        [(hbValue)]="marks"
      >
        <hb-toggle hbValue="bold" hbIcon="phosphorTextB" />
        <hb-toggle hbValue="italic" hbIcon="phosphorTextItalic" />
        <hb-toggle hbValue="underline" hbIcon="phosphorTextUnderline" />
        <hb-toggle hbValue="strike" hbIcon="phosphorTextStrikethrough" hbDisabled />
      </hb-toggle-group>

      <p class="font-mono text-[12px] text-muted-foreground">
        marks: [{{ $any(marks()).join(', ') }}]
      </p>
    </div>
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class HbDemoToggleGroupMultipleComponent {
  protected readonly marks = signal<unknown>(['bold', 'italic']);
}

import { ChangeDetectionStrategy, Component, signal } from '@angular/core';
import { provideIcons } from '@ng-icons/core';
import {
  phosphorTextAlignCenter,
  phosphorTextAlignJustify,
  phosphorTextAlignLeft,
  phosphorTextAlignRight,
} from '@ng-icons/phosphor-icons/regular';

import { HbToggleImports } from '@herbst/ui';

@Component({
  selector: 'hb-demo-toggle-group-single',
  imports: [HbToggleImports],
  viewProviders: [
    provideIcons({
      phosphorTextAlignLeft,
      phosphorTextAlignCenter,
      phosphorTextAlignRight,
      phosphorTextAlignJustify,
    }),
  ],
  template: `
    <div class="flex flex-col gap-4">
      <hb-toggle-group hbVariant="outline" hbAriaLabel="Text alignment" [(hbValue)]="align">
        <hb-toggle hbValue="left" hbIcon="phosphorTextAlignLeft" />
        <hb-toggle hbValue="center" hbIcon="phosphorTextAlignCenter" />
        <hb-toggle hbValue="right" hbIcon="phosphorTextAlignRight" />
        <hb-toggle hbValue="justify" hbIcon="phosphorTextAlignJustify" hbDisabled />
      </hb-toggle-group>

      <hb-toggle-group hbSize="sm" [hbConnected]="false" [hbRollable]="false" [(hbValue)]="view">
        <hb-toggle hbValue="grid">Grid</hb-toggle>
        <hb-toggle hbValue="list">List</hb-toggle>
        <hb-toggle hbValue="table">Table</hb-toggle>
      </hb-toggle-group>

      <p class="font-mono text-[12px] text-muted-foreground">
        align: {{ align() }} · view: {{ view() }}
      </p>
    </div>
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class HbDemoToggleGroupSingleComponent {
  protected readonly align = signal<unknown>('left');
  protected readonly view = signal<unknown>('grid');
}
